# freeze_gate.py
import os
import sys
import requests
from dataclasses import dataclass
from enum import Enum

class FreezeLevel(Enum):
    NORMAL = 'normal'
    SOFT   = 'soft'
    HARD   = 'hard'
    EXHAUSTED = 'exhausted'

@dataclass
class BudgetStatus:
    slo_id: str
    budget_remaining_fraction: float  # 0.0 = exhausted, 1.0 = full

    @property
    def freeze_level(self) -> FreezeLevel:
        if self.budget_remaining_fraction <= 0.0:
            return FreezeLevel.EXHAUSTED
        elif self.budget_remaining_fraction <= 0.05:
            return FreezeLevel.HARD
        elif self.budget_remaining_fraction <= 0.20:
            return FreezeLevel.SOFT
        return FreezeLevel.NORMAL

def fetch_budget_status(prometheus_url: str, slo_ids: list[str]) -> list[BudgetStatus]:
    statuses = []
    for slo_id in slo_ids:
        query = (
            f'slo:error_budget:remaining{{slo_id="{slo_id}"}}'
        )
        resp = requests.get(
            f'{prometheus_url}/api/v1/query',
            params={'query': query},
            timeout=5,
        )
        data = resp.json()['data']['result']
        if data:
            remaining = float(data[0]['value'][1])
            statuses.append(BudgetStatus(slo_id=slo_id, budget_remaining_fraction=remaining))
    return statuses

def check_deploy_allowed(
    statuses: list[BudgetStatus],
    deploy_type: str,  # 'feature', 'hotfix', 'rollback'
    override_approved: bool = False,
) -> tuple[bool, str]:
    worst = max(statuses, key=lambda s: [
        FreezeLevel.EXHAUSTED, FreezeLevel.HARD, FreezeLevel.SOFT, FreezeLevel.NORMAL
    ].index(s.freeze_level))

    level = worst.freeze_level

    if level == FreezeLevel.NORMAL:
        return True, 'OK'

    if level == FreezeLevel.SOFT:
        if deploy_type in ('hotfix', 'rollback'):
            return True, 'Allowed under soft freeze (hotfix/rollback)'
        if override_approved:
            return True, 'Soft freeze exception approved by SRE on-call'
        return False, (
            f'SOFT FREEZE: budget remaining {worst.budget_remaining_fraction:.0%}. '
            'Feature deploys require SRE on-call approval.'
        )

    if level == FreezeLevel.HARD:
        if deploy_type == 'rollback':
            return True, 'Rollback allowed under hard freeze'
        if override_approved:
            return True, 'Hard freeze exception approved by Engineering VP'
        return False, (
            f'HARD FREEZE: budget remaining {worst.budget_remaining_fraction:.0%}. '
            'All deploys blocked. Engineering VP approval required.'
        )

    # EXHAUSTED
    if deploy_type == 'rollback' and override_approved:
        return True, 'Emergency rollback approved (budget exhausted)'
    return False, (
        'BUDGET EXHAUSTED: SLO violated. '
        'Only emergency rollbacks with C-level approval.'
    )

if __name__ == '__main__':
    PROM = os.environ['PROMETHEUS_URL']
    SLO_IDS = ['availability', 'latency_p95', 'eval_quality', 'safety']
    statuses = fetch_budget_status(PROM, SLO_IDS)
    deploy_type = sys.argv[1] if len(sys.argv) > 1 else 'feature'
    allowed, reason = check_deploy_allowed(statuses, deploy_type)
    print(f'{"ALLOWED" if allowed else "BLOCKED"}: {reason}')
    sys.exit(0 if allowed else 1)
